    if (i >= p.length) have[s.charCodeAt(i - p.length) - 97]--;
    if (i >= p.length - 1) {
      let ok = true;
      for (let k = 0; k < 26; k++) if (need[k] !== have[k]) { ok = false; break; }
      if (ok) out.push(i - p.length + 1);
    }
  }
  return out;
}
```

**Time**: O(n*26). **Space**: O(1).

