editorial:
**Rolling hash idea**: Treat each char as a digit in base B (e.g., 257) modulo a big prime `M`. Hash of a window updates in O(1) when we slide one char.

```javascript
function rabinKarp(text, pattern) {
  if (pattern === '') return 0;
  const n = text.length, m = pattern.length;
  if (m > n) return -1;
  const B = 257, M = 1_000_000_007n;
  let pHash = 0n, tHash = 0n, pow = 1n;
  for (let i = 0; i < m; i++) {
    pHash = (pHash * BigInt(B) + BigInt(pattern.charCodeAt(i))) % M;
    tHash = (tHash * BigInt(B) + BigInt(text.charCodeAt(i))) % M;
    if (i < m - 1) pow = (pow * BigInt(B)) % M;
  }
  for (let i = 0; i + m <= n; i++) {
    if (pHash === tHash && text.slice(i, i + m) === pattern) return i;
    if (i + m < n) {
      tHash = (tHash - BigInt(text.charCodeAt(i)) * pow % M + M * M) % M;
      tHash = (tHash * BigInt(B) + BigInt(text.charCodeAt(i + m))) % M;
    }
  }
  return -1;
}
```

**Time**: O(n + m) average; O(n*m) worst-case under collisions. **Space**: O(1).

