```javascript
function parseSeatCodes(codes) {
  const isUpper = c => c >= 'A' && c <= 'Z';
  const isDigit = c => c >= '0' && c <= '9';
  let valid = 0;
  let maxRow = '';
  for (const code of codes) {
    let i = 0;
    while (i < code.length && i < 2 && isUpper(code[i])) i++;
    if (i === 0) continue; // need at least 1 letter
    const row = code.slice(0, i);
    let j = i;
    while (j < code.length && isDigit(code[j])) j++;
    if (j === i || j !== code.length) continue; // need digits, nothing else after
