    if (numStr.length > 2) continue;
    if (numStr.length > 1 && numStr[0] === '0') continue; // leading zero
    const n = parseInt(numStr, 10);
    if (n < 1 || n > 99) continue;
    valid++;
    if (row > maxRow) maxRow = row;
  }
  return [valid, maxRow];
}
